let clamp = (value, lo, hi) -> min(max(value, lo), hi);

let lerp = (a, b, t) -> a + (b - a) * t;

let inRange = (value, lo, hi) -> value >= lo && value <= hi;

{
  clamp: clamp,
  lerp: lerp,
  inRange: inRange
}

let mySum = (arr) -> reduce(arr, +, 0);

let average = (arr) -> mySum(arr) / count(arr);

let variance = (arr) -> do
  let avg = average(arr);
  let squaredDiffs = map(arr, (x) -> (x - avg) ^ 2);
  average(squaredDiffs)
end;

{
  sum: mySum,
  average: average,
  variance: variance
}

let { clamp, lerp } = import("./lib/math.dvala");
let { average } = import("./lib/stats.dvala");
let { pi } = import("./lib/constants.dvala");

let values = [3, 7, 2, 9, 4];
let avg = average(values);
let clamped = clamp(avg, 0, 5);
let interpolated = lerp(0, pi, 0.5);

{
  avg: avg,
  clamped: clamped,
  interpolated: interpolated
}
